#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char row[100005], col[100005];
        scanf("%s", row);
        scanf("%s", col);
        int N = strlen(col);
        int M = strlen(row);
        int Q;
        scanf("%d", &Q);
        int dp[N+1][M+1];
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= M; j++) {
                dp[i][j] = -1;
            }
        }
        for (int i = 1; i <= N; i++) {
            dp[i][0] = col[i-1] - '0';
        }
        for (int j = 1; j <= M; j++) {
            dp[0][j] = row[j-1] - '0';
        }
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= M; j++) {
                if (dp[i-1][j] == 0 && dp[i][j-1] == 0) {
                    dp[i][j] = 1;
                } else if (dp[i-1][j] == 1 && dp[i][j-1] == 1) {
                    dp[i][j] = 0;
                } else if (dp[i-1][j] == 0 && dp[i][j-1] == 1) {
                    dp[i][j] = 1;
                } else if (dp[i-1][j] == 1 && dp[i][j-1] == 0) {
                    dp[i][j] = 1;
                }
            }
        }
        while (Q--) {
            int x, y;
            scanf("%d %d", &x, &y);
            printf("%d", dp[x][y]);
        }
        printf("\n");
    }
    return 0;
}

