import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String row = sc.next();
            String col = sc.next();
            int N = col.length();
            int M = row.length();
            int Q = sc.nextInt();
            int[][] dp = new int[N+1][M+1];
            for (int i = 0; i <= N; i++) {
                for (int j = 0; j <= M; j++) {
                    dp[i][j] = -1;
                }
            }
            for (int i = 1; i <= N; i++) {
                dp[i][0] = col.charAt(i-1) - '0';
            }
            for (int j = 1; j <= M; j++) {
                dp[0][j] = row.charAt(j-1) - '0';
            }
            for (int i = 1; i <= N; i++) {
                for (int j = 1; j <= M; j++) {
                    if (dp[i-1][j] == 0 && dp[i][j-1] == 0) {
                        dp[i][j] = 1;
                    } else if (dp[i-1][j] == 1 && dp[i][j-1] == 1) {
                        dp[i][j] = 0;
                    } else if (dp[i-1][j] == 0 && dp[i][j-1] == 1) {
                        dp[i][j] = 1;
                    } else if (dp[i-1][j] == 1 && dp[i][j-1] == 0) {
                        dp[i][j] = 1;
                    }
                }
            }
            while (Q-- > 0) {
                int x = sc.nextInt();
                int y = sc.nextInt();
                System.out.print(dp[x][y]);
            }
            System.out.println();
        }
    }
}

